package com.example.sso.controller;

import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;

import java.io.IOException;
import java.net.URI;
import java.net.URISyntaxException;
import java.util.List;

@Controller
public class LogoutController {

    @Value("${sso.allowed-redirect-domains:}")
    private List<String> allowedRedirectDomains;

    @Value("${sso.default-redirect-url:https://www.example.com}")
    private String defaultRedirectUrl;

    @GetMapping("/logout")
    public void logout(HttpServletRequest request, HttpServletResponse response) throws IOException {
        // Invalidate the session
        HttpSession session = request.getSession(false);
        if (session != null) {
            session.invalidate();
        }

        String nextUrl = request.getParameter("next");

        if (isValidRedirectUrl(nextUrl)) {
            response.sendRedirect(nextUrl);
        } else {
            response.sendRedirect(defaultRedirectUrl);
        }
    }

    private boolean isValidRedirectUrl(String url) {
        if (url == null || url.isBlank()) {
            return false;
        }

        // Block protocol-relative URLs (e.g., //evil.com)
        if (url.startsWith("//")) {
            return false;
        }

        // Block javascript:, data:, vbscript:, and other dangerous schemes
        String lowerUrl = url.toLowerCase().trim();
        if (lowerUrl.startsWith("javascript:") || lowerUrl.startsWith("data:") ||
                lowerUrl.startsWith("vbscript:") || lowerUrl.startsWith("mailto:")) {
            return false;
        }

        // Only allow http and https schemes
        URI uri;
        try {
            uri = new URI(url);
        } catch (URISyntaxException e) {
            return false;
        }

        String scheme = uri.getScheme();
        if (scheme == null || (!scheme.equalsIgnoreCase("https") && !scheme.equalsIgnoreCase("http"))) {
            return false;
        }

        String host = uri.getHost();
        if (host == null || host.isBlank()) {
            return false;
        }

        // Check that the host matches one of the allowed domains
        // Supports exact match and subdomain match
        for (String allowedDomain : allowedRedirectDomains) {
            String trimmedDomain = allowedDomain.trim().toLowerCase();
            String lowerHost = host.toLowerCase();

            if (lowerHost.equals(trimmedDomain)) {
                return true;
            }

            // Allow subdomains: e.g., app.example.com matches allowed domain example.com
            if (lowerHost.endsWith("." + trimmedDomain)) {
                return true;
            }
        }

        return false;
    }
}